<template>
  <router-link class="commons"
  :class="select ? 'selects' : 'noSelect'"
  :to="to"
  @click="$store.commit('name_change', this.text)"
  >{{ text }}</router-link>
</template>

<script>
export default {
  name: 'commons',
  props: {
    text: String,
    to: String,
    index: Number
  },
  computed: {
    select() {
      // 当前序列号对应状态管理的序列号
      if(this.index == this.$store.state.expo.index) {
        // 提交名称
        this.$store.commit('name_change', this.text)
        // 显示选中css
        return true
      } else {
        return false
      }
    }
  }
}
</script>

