// 左菜单，包含小屏状态的页面
<template>
  <transition name="mask">
    <!-- 遮罩层，负责关闭小导航菜单内容，如果改为全局冒泡阻止法，有bug -->
    <!-- 选择性显示 -->
    <div class="mask"
    @click.stop="close()"
    @touchstart.passive="finger_into($event)"
    @touchmove.prevent="_finger_slide($event)"
    @touchend.passive="finger_leave()"
    v-show="$store.state.min_nav_body"
    />
  </transition>

  <transition name="into" v-if="$store.state.min_nav">
    <!-- 小导航链接 -->
    <min-nav-router class="min-nav-router" :style="left_move" v-show="$store.state.min_nav_body" />
  </transition>

  <transition name="into" v-if="$store.state.min_nav">
    <div class="left-bar"
    :style="left_move"
    v-show="$store.state.min_nav_body">
      <!-- 其他内容插槽 -->
      <div class="other">
        <slot name="other" />
      </div>
    </div>
  </transition>

  <transition name="into" v-if="$store.state.min_nav">
    <!-- 单击刷新页面，用于清理菜单栏 -->
    <div class="rotate_box" :style="left_move" v-show="$store.state.min_nav_body">
      <rotate class="rotate" @click="$router.go(0)" :size_color="true" />
    </div>
  </transition>
</template>

<script>
import minNavRouter from 'common/nav/min/min-nav-router.vue'
import rotate from 'common/Intro/brief/left/rotate.vue'

export default {
  name: 'left-bar',
  data() {
    return {
      // 手指初始值
      x: 0,
      // 移动倍数
      multiple: 1.2,
      // 菜单left值
      left_move_distance: 0,
      left_move: {},
      timer: -1 // 存放计时器
    }
  },
  components: {
    minNavRouter,
    rotate
  },
  methods: {
    // 关闭菜单
    close() {
      // 小导航内容有个透明遮罩层，点击关闭小导航内容
      this.$store.commit('min_nav_body_change', false)
    },
    // 手指进入时
    finger_into(e) {
      // 获取坐标初值
      this.x = e.touches[0].pageX
    },
    // 手指滑动时，节流方法
    _finger_slide(e) {
      if(this.timer == -1) {

        this.timer = setTimeout(() => {
          this.timer = -1
        }, 9)

        this.finger_slide(e)
      }
    },
    // 手指滑动时
    finger_slide(e) {
      if((e.touches[0].pageX - this.x) * this.multiple > 0) {
        // 如果运动后的left值大于0，left值为0
        this.left_move_distance = (e.touches[0].pageX - this.x) * this.multiple
        this.left_move = {
          transform: 'translateX(' + 0 + 'px)'
        }
      } else {
        // 如果left值小于0
        // 比较坐标初值的宽度进行移动
        this.left_move_distance = (e.touches[0].pageX - this.x) * this.multiple
        this.left_move = {
          transform: 'translateX(' + this.left_move_distance + 'px)'
        }
      }
    },
    // 手指离开时
    finger_leave() {
      // 屏幕宽度的70%为左菜单占比，滑动距离为滑动值的40%
      if (this.left_move_distance < -this.w_7_n) {
        // 动画移动至-100%
        new Promise(resolve => {
          // 关闭菜单
          this.close()
          setTimeout(() => {
            resolve()
          }, 400)
        }).then(() => {
          // 弹回菜单原位置
          // 还原left_move初值
          this.left_move_distance = 0
          this.left_move = {
            transform: 'translateX(' + this.left_move_distance + 'px)'
          }
        })
      } else {
        // 如果没有超过滑动距离
        // 回弹动画
        // 使用计时器实现动画效果
        let bounce_back = setInterval(() => {
          if(this.left_move_distance + this.multiple * 10 >= 0) {
            clearTimeout(bounce_back)
            this.left_move_distance = 0
            // 弹回菜单
            this.left_move = {
              transform: 'translateX(' + this.left_move_distance + 'px)'
            }
          } else {
            this.left_move_distance += this.multiple * 8
            // 弹回菜单
            this.left_move = {
              transform: 'translateX(' + this.left_move_distance + 'px)'
            }
          }
        }, 17)
      }
    }
  },
  computed: {
    // 返回滑动值
    w_7_n() {
      return screen.width * .7 * .35
    }
  }
}
</script>

